 1	import * as React from 'react';
 2	import { Dropdown, DropdownItem, MenuToggle } from '@patternfly/react-core';
 3	import { useCustomTranslation } from '../useCustomTranslationHook';
 4	
 5	export const ActionDropdown: React.FC<ActionDropdownProps> = ({
 6	  id,
 7	  text,
 8	  dropdownItems,
 9	  dropdownPosition,
10	  isDisabled,
11	  isPlain,
12	  toggleVariant,
13	  onToggle,
14	  onSelect,
15	}) => {
16	  const [isOpen, setOpen] = React.useState<boolean>(false);
17	  const { t } = useCustomTranslation();
18	  const toggleRef = React.useRef<HTMLButtonElement>();
19	
20	  const onClick = (key: string) => {
21	    onSelect(key);
22	    setOpen(false);
23	  };
24	
25	  return (
26	    <Dropdown
27	      popperProps={{
28	        position: dropdownPosition || 'right',
29	      }}
30	      toggle={{
31	        toggleNode: (
32	          <MenuToggle
33	            ref={toggleRef}
34	            aria-label={t('Select input')}
35	            variant={toggleVariant || 'default'}
36	            id={id}
37	            isDisabled={isDisabled}
38	            onClick={() => {
39	              setOpen(!isOpen);
40	              !!onToggle && onToggle(!isOpen);
41	            }}
42	            isExpanded={isOpen}
43	          >
44	            {text}
45	          </MenuToggle>
46	        ),
47	        toggleRef,
48	      }}
49	      isOpen={isOpen}
50	      isPlain={isPlain}
51	    >
52	      {dropdownItems.map((item) => (
53	        <DropdownItem
54	          key={item.id}
55	          isDisabled={item?.isDisabled}
56	          onClick={() => onClick(item.id)}
57	        >
58	          {item.text}
59	        </DropdownItem>
60	      ))}
61	    </Dropdown>
62	  );
63	};
64	
65	export type ActionDropdownItems = {
66	  id: string;
67	  isDisabled?: boolean;
68	  text: string | React.ReactNode;
69	};
70	
71	export type ToggleVariant = 'primary' | 'secondary' | 'default';
72	
73	export type ActionDropdownProps = {
74	  dropdownItems: ActionDropdownItems[];
75	  text: string;
76	  isDisabled?: boolean;
77	  id: string;
78	  toggleVariant?: ToggleVariant;
79	  dropdownPosition?: 'right' | 'left' | 'center' | 'start' | 'end';
80	  isPlain?: boolean;
81	  onSelect: (id: string) => void;
82	  onToggle?: (isOpen?: boolean) => void;
83	};

